{
  "data_sources": [
    {
      "name": "API_Access_Logs",
      "type": "Log Aggregator",
      "connection_config": {
        "type": "ELK Stack",
        "index": "fastapi-access-logs-*",
        "fields": [
          "timestamp",
          "method",
          "path",
          "status_code",
          "response_time_ms",
          "user_id"
        ]
      }
    },
    {
      "name": "API_Error_Logs",
      "type": "Log Aggregator",
      "connection_config": {
        "type": "ELK Stack",
        "index": "fastapi-error-logs-*",
        "fields": [
          "timestamp",
          "level",
          "message",
          "path",
          "status_code",
          "exception_type"
        ]
      }
    },
    {
      "name": "Application_Metrics_DB",
      "type": "PostgreSQL",
      "connection_config": {
        "host": "localhost",
        "port": 5432,
        "database": "fastapi_metrics",
        "user": "metrics_user",
        "password_env_var": "DB_METRICS_PASSWORD"
      }
    },
    {
      "name": "System_Resource_Monitor",
      "type": "Prometheus",
      "connection_config": {
        "endpoint": "http://localhost:9090",
        "query_language": "PromQL"
      }
    }
  ],
  "kpis": [
    {
      "name": "API Uptime",
      "formula": "1 - (COUNT(DISTINCT timestamp WHERE status_code >= 500) / COUNT(DISTINCT timestamp)) * 100",
      "target": "99.9%",
      "frequency": "real-time"
    },
    {
      "name": "Average API Response Time",
      "formula": "AVG(response_time_ms)",
      "target": "200ms",
      "frequency": "real-time"
    },
    {
      "name": "API Error Rate (5xx)",
      "formula": "(COUNT(status_code >= 500) / COUNT(*)) * 100",
      "target": "1%",
      "frequency": "real-time"
    },
    {
      "name": "Successful Login Rate",
      "formula": "(COUNT(login_attempts WHERE status = 'success') / COUNT(login_attempts)) * 100",
      "target": "95%",
      "frequency": "daily"
    },
    {
      "name": "Task Completion Rate",
      "formula": "(COUNT(tasks WHERE status = 'completed') / COUNT(tasks)) * 100",
      "target": "80%",
      "frequency": "weekly"
    },
    {
      "name": "New Users Registered (Daily)",
      "formula": "COUNT(users WHERE created_at >= NOW() - INTERVAL '1 day')",
      "target": "10",
      "frequency": "daily"
    }
  ],
  "dashboards": [
    {
      "name": "API Performance Overview",
      "description": "Monitors the overall health and performance of the FastAPI backend.",
      "widgets": [
        {
          "type": "metric",
          "title": "Total API Requests (Last 24h)",
          "data_source": "API_Access_Logs",
          "query": "SELECT COUNT(*) FROM fastapi-access-logs-* WHERE timestamp >= NOW() - INTERVAL '24 hours'",
          "visualization_config": {
            "value_format": "0,0"
          }
        },
        {
          "type": "metric",
          "title": "Avg. Response Time (Last 24h)",
          "data_source": "API_Access_Logs",
          "query": "SELECT AVG(response_time_ms) FROM fastapi-access-logs-* WHERE timestamp >= NOW() - INTERVAL '24 hours'",
          "visualization_config": {
            "value_format": "0.00 ms",
            "thresholds": [
              { "value": 200, "color": "green" },
              { "value": 500, "color": "orange" },
              { "value": 1000, "color": "red" }
            ]
          }
        },
        {
          "type": "metric",
          "title": "API Error Rate (5xx, Last 24h)",
          "data_source": "API_Access_Logs",
          "query": "SELECT (COUNT(status_code >= 500) / COUNT(*)) * 100 FROM fastapi-access-logs-* WHERE timestamp >= NOW() - INTERVAL '24 hours'",
          "visualization_config": {
            "value_format": "0.00%",
            "thresholds": [
              { "value": 1, "color": "green" },
              { "value": 3, "color": "orange" },
              { "value": 5, "color": "red" }
            ]
          }
        },
        {
          "type": "chart",
          "title": "API Request Volume by Endpoint (Last 7 Days)",
          "data_source": "API_Access_Logs",
          "query": "SELECT DATE_TRUNC('day', timestamp) AS day, path, COUNT(*) FROM fastapi-access-logs-* WHERE timestamp >= NOW() - INTERVAL '7 days' GROUP BY day, path ORDER BY day, COUNT(*) DESC",
          "visualization_config": {
            "chart_type": "line",
            "x_axis": { "field": "day", "label": "Date", "type": "time" },
            "y_axis": { "field": "count", "label": "Requests", "type": "linear" },
            "series": { "field": "path", "type": "split" }
          }
        },
        {
          "type": "chart",
          "title": "Average Response Time by Endpoint (Last 24h)",
          "data_source": "API_Access_Logs",
          "query": "SELECT path, AVG(response_time_ms) AS avg_response_time FROM fastapi-access-logs-* WHERE timestamp >= NOW() - INTERVAL '24 hours' GROUP BY path ORDER BY avg_response_time DESC LIMIT 10",
          "visualization_config": {
            "chart_type": "bar",
            "x_axis": { "field": "path", "label": "Endpoint" },
            "y_axis": { "field": "avg_response_time", "label": "Avg. Response Time (ms)" }
          }
        },
        {
          "type": "table",
          "title": "Top 10 Slowest API Endpoints (Last Hour)",
          "data_source": "API_Access_Logs",
          "query": "SELECT path, AVG(response_time_ms) AS avg_response_time, COUNT(*) AS request_count FROM fastapi-access-logs-* WHERE timestamp >= NOW() - INTERVAL '1 hour' GROUP BY path ORDER BY avg_response_time DESC LIMIT 10",
          "visualization_config": {
            "columns": [
              { "field": "path", "label": "Endpoint" },
              { "field": "avg_response_time", "label": "Avg. Response Time (ms)", "format": "0.00" },
              { "field": "request_count", "label": "Requests" }
            ]
          }
        }
      ]
    },
    {
      "name": "Authentication & User Activity",
      "description": "Monitors user registration, login, and authentication system health.",
      "widgets": [
        {
          "type": "metric",
          "title": "Total Registered Users",
          "data_source": "Application_Metrics_DB",
          "query": "SELECT COUNT(*) FROM users",
          "visualization_config": {
            "value_format": "0,0"
          }
        },
        {
          "type": "metric",
          "title": "Successful Logins (Last 24h)",
          "data_source": "Application_Metrics_DB",
          "query": "SELECT COUNT(*) FROM login_attempts WHERE status = 'success' AND timestamp >= NOW() - INTERVAL '24 hours'",
          "visualization_config": {
            "value_format": "0,0"
          }
        },
        {
          "type": "metric",
          "title": "Failed Logins (Last 24h)",
          "data_source": "Application_Metrics_DB",
          "query": "SELECT COUNT(*) FROM login_attempts WHERE status = 'failed' AND timestamp >= NOW() - INTERVAL '24 hours'",
          "visualization_config": {
            "value_format": "0,0",
            "thresholds": [
              { "value": 10, "color": "green" },
              { "value": 50, "color": "orange" },
              { "value": 100, "color": "red" }
            ]
          }
        },
        {
          "type": "chart",
          "title": "User Registration Trend (Last 30 Days)",
          "data_source": "Application_Metrics_DB",
          "query": "SELECT DATE_TRUNC('day', created_at) AS day, COUNT(*) FROM users WHERE created_at >= NOW() - INTERVAL '30 days' GROUP BY day ORDER BY day",
          "visualization_config": {
            "chart_type": "line",
            "x_axis": { "field": "day", "label": "Date", "type": "time" },
            "y_axis": { "field": "count", "label": "New Users" }
          }
        },
        {
          "type": "chart",
          "title": "Login Success vs. Failure Rate (Last 7 Days)",
          "data_source": "Application_Metrics_DB",
          "query": "SELECT status, COUNT(*) FROM login_attempts WHERE timestamp >= NOW() - INTERVAL '7 days' GROUP BY status",
          "visualization_config": {
            "chart_type": "pie",
            "label_field": "status",
            "value_field": "count"
          }
        },
        {
          "type": "table",
          "title": "Recent Failed Login Attempts",
          "data_source": "Application_Metrics_DB",
          "query": "SELECT username, timestamp, ip_address FROM login_attempts WHERE status = 'failed' ORDER BY timestamp DESC LIMIT 20",
          "visualization_config": {
            "columns": [
              { "field": "username", "label": "Username" },
              { "field": "timestamp", "label": "Time" },
              { "field": "ip_address", "label": "IP Address" }
            ]
          }
        }
      ]
    },
    {
      "name": "Task Management Activity",
      "description": "Tracks task creation, completion, and modification trends.",
      "widgets": [
        {
          "type": "metric",
          "title": "Total Tasks Created",
          "data_source": "Application_Metrics_DB",
          "query": "SELECT COUNT(*) FROM tasks",
          "visualization_config": {
            "value_format": "0,0"
          }
        },
        {
          "type": "metric",
          "title": "Total Tasks Completed (Last 30 Days)",
          "data_source": "Application_Metrics_DB",
          "query": "SELECT COUNT(*) FROM tasks WHERE status = 'completed' AND completed_at >= NOW() - INTERVAL '30 days'",
          "visualization_config": {
            "value_format": "0,0"
          }
        },
        {
          "type": "metric",
          "title": "Average Tasks per User",
          "data_source": "Application_Metrics_DB",
          "query": "SELECT AVG(task_count) FROM (SELECT user_id, COUNT(*) AS task_count FROM tasks GROUP BY user_id) AS user_tasks",
          "visualization_config": {
            "value_format": "0.00"
          }
        },
        {
          "type": "chart",
          "title": "Task Creation Trend (Last 90 Days)",
          "data_source": "Application_Metrics_DB",
          "query": "SELECT DATE_TRUNC('day', created_at) AS day, COUNT(*) FROM tasks WHERE created_at >= NOW() - INTERVAL '90 days' GROUP BY day ORDER BY day",
          "visualization_config": {
            "chart_type": "line",
            "x_axis": { "field": "day", "label": "Date", "type": "time" },
            "y_axis": { "field": "count", "label": "Tasks Created" }
          }
        },
        {
          "type": "chart",
          "title": "Task Status Distribution",
          "data_source": "Application_Metrics_DB",
          "query": "SELECT status, COUNT(*) FROM tasks GROUP BY status",
          "visualization_config": {
            "chart_type": "pie",
            "label_field": "status",
            "value_field": "count"
          }
        },
        {
          "type": "table",
          "title": "Recently Modified Tasks",
          "data_source": "Application_Metrics_DB",
          "query": "SELECT t.title, u.username AS owner, t.status, t.updated_at FROM tasks t JOIN users u ON t.user_id = u.id ORDER BY t.updated_at DESC LIMIT 10",
          "visualization_config": {
            "columns": [
              { "field": "title",
